-- ══════════════════════════════════════════════════════════════
-- seed-athlete-docs.sql — Documents des athlètes (bytea)
-- Base : glop (PostgreSQL)
-- Même certificat médical + passeport pour les 40 athlètes
-- ══════════════════════════════════════════════════════════════

UPDATE athletes
SET certificat_medical = decode('', 'hex'),
    passport           = decode('', 'hex')
WHERE id BETWEEN 2 AND 41;
